const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 0);
const dayOfYear = Math.floor((now - startOfYear) / 86400000);
const weekOfYear = Math.floor(dayOfYear / 7);
const weekOfMonth = Math.ceil(now.getDate() / 7);

const industries = [
  'healthcare and medical clinics',
  'professional services such as legal accounting and consulting firms',
  'retail and ecommerce small businesses',
  'hospitality restaurants and food service',
  'trades and home services like HVAC plumbing electrical and roofing',
  'nonprofits and community organizations',
  'education and training providers'
];
const industry = industries[weekOfYear % industries.length];

const categories = ['automation_tip', 'service_spotlight', 'industry_insight', 'call_to_action'];
const category = categories[(weekOfMonth - 1) % 4];

const researchQueries = {
  automation_tip: `Find 2 to 3 recent practical automation use cases or productivity wins from the last 30 days for ${industry}. Focus on time saved, processes improved, real world examples. Be specific. Cite sources.`,
  service_spotlight: `Find 2 to 3 recent examples from the last 30 days of small ${industry} using AI workflow automation, document automation, compliance automation, or cybersecurity to improve operations. Cite sources.`,
  industry_insight: `Find the latest trends, news, or developments from the last 14 days in AI and automation affecting ${industry}. Focus on practical implications for small business owners. Cite sources.`,
  call_to_action: `Find 2 to 3 recent statistics or data points from the last 60 days showing the benefits of business automation for small businesses, particularly ${industry}. Focus on time savings, cost reductions, error reductions. Cite sources.`
};

return [{ json: {
  category,
  industry,
  weekOfMonth,
  weekOfYear,
  research_query: researchQueries[category],
  generatedAt: now.toISOString()
}}];

const ctx = $('Build Post Prompt').item.json;
const researchRaw = $('Research Trending Topics').first().json;
const research = (researchRaw.message && researchRaw.message.content)
  || researchRaw.content
  || (researchRaw.choices && researchRaw.choices[0] && researchRaw.choices[0].message && researchRaw.choices[0].message.content)
  || (typeof researchRaw === 'string' ? researchRaw : JSON.stringify(researchRaw).substring(0, 2000));

const recentRaw = $('Fetch Recent Posts').all();
const recentSummary = recentRaw.length > 0
  ? recentRaw.map((item, i) => {
      const p = item.json;
      const date = new Date(p.published_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      const preview = (p.post_text || '').substring(0, 120).replace(/\n/g, ' ');
      return `[${i + 1}] Category: ${p.category} | Date: ${date} | Preview: "${preview}..."`;
    }).join('\n')
  : 'No previous posts found.';

const ctaUrl = (ctx.category === 'service_spotlight' || ctx.category === 'call_to_action')
  ? 'yourcompany.com/request-assessment'
  : 'yourcompany.com';

const prompt = `Write a Google Business Profile post for Your Company Inc., an AI and automation consultancy serving small businesses across multiple industries.

INDUSTRY FOCUS THIS WEEK: ${ctx.industry}
CATEGORY: ${ctx.category}

RESEARCH FINDINGS (use these for credibility, paraphrase, do not copy verbatim, do not include URLs or citation markers in the post):
${research}

VOICE AND TONE:
- Educational and curious, never alarmist
- Confident but humble, acknowledge nuance, trade offs, and limits
- Plain English, accessible to a non technical owner
- Never use the words leverage or streamline
- Never use em dashes
- No fear based phrases like losing revenue, walking out the door, before it is too late
- Avoid framing customers, patients, or clients as transactions or sources of money

STRUCTURE (200 to 280 words):
1. HOOK (1 to 2 sentences): A genuine insight, statistic, or trend from the research
2. CONTEXT (2 to 3 sentences): What is actually happening in ${ctx.industry}, what is possible now
3. NUANCE (1 to 2 sentences): Trade offs, guardrails, what NOT to automate, where humans still matter
4. YourCo ANGLE (1 to 2 sentences): How we approach this with audit trails, human in the loop, industry fit SOPs, sensible guardrails
5. SOFT CTA (1 sentence): Inviting close. Examples: Curious how this could work in your business, or Want to think it through together

CATEGORY SPECIFIC FOCUS:
- automation_tip: Practical use case showing how automation saves time or removes friction
- service_spotlight: Highlight one YourCo service area such as IT managed services, cybersecurity, compliance automation, or AI workflows with a real example
- industry_insight: A trend or development affecting ${ctx.industry}, broadly applicable
- call_to_action: Invite small business owners to assess their operations as discovery, not pressure

Your Company CONTEXT:
- Tagline: Automate. Relentlessly. Ruthlessly.
- Serves small businesses across ALL industries
- Emphasizes guardrails, human in the loop, audit trails, SOPs, security, compliance
- Builds systems that fit how a business actually operates, not generic templates
- Based in Central Florida, serving small businesses nationally

WHAT TO AVOID:
- Specific made up business names or cities, only use what is in the research
- Overclaiming AI capabilities, prefer modern automation can help with X over AI now does X
- Treating customers, patients, or clients as revenue sources
- Generic LinkedIn influencer phrasing
- Hashtags, em dashes, emojis (unless very subtle)
- URLs or citation markers in the post body

CTA URL TO REFERENCE: ${ctaUrl}
End with a soft invitation that includes the URL naturally.

DO NOT REPEAT - Recent posts published:
${recentSummary}

Pick a different angle, example, and hook from the recent posts. Same industry is acceptable if angle differs significantly.`;

return [{ json: {
  ...ctx,
  prompt,
  research_summary: research.substring(0, 500),
  recentPostCount: recentRaw.length
}}];

const postText = $input.first().json.output || '';
if (!postText) throw new Error('Claude returned empty post');
const ctx = $('Merge Prompt + History').item.json;
// Google Business Profile rejects posts over 1500 chars ("Bad request").
// Trim to a clean sentence boundary under 1450 so we never trip it.
let txt = postText.trim();
const MAX = 1450;
if (txt.length > MAX) {
  let cut = txt.slice(0, MAX);
  const stop = Math.max(cut.lastIndexOf('. '), cut.lastIndexOf('! '), cut.lastIndexOf('? '), cut.lastIndexOf('\n'));
  cut = (stop > MAX * 0.6) ? cut.slice(0, stop + 1) : cut.replace(/\s+\S*$/, '');
  txt = cut.trim();
}
return [{ json: {
  post_text: txt,
  post_chars: txt.length,
  category: ctx.category,
  industry: ctx.industry,
  week_of_month: ctx.weekOfMonth,
  week_of_year: ctx.weekOfYear,
  generated_at: ctx.generatedAt
}}];

